module stimulus_gen (input logic clk, output logic [7:0] d, output logic reset); task wavedrom_start; endtask task wavedrom_stop; endtask task reset_test; bit arfail, srfail, datafail; @(posedge clk); @(posedge clk) reset <= 0; repeat(3) @(posedge clk); @(negedge clk) begin datafail = !tb_match; reset <= 1; end @(posedge clk) arfail = !tb_match; @(posedge clk) begin srfail = !tb_match; reset <= 0; end if (srfail) $display("Hint: Reset issue"); else if (arfail && async) $display("Reset sync"); endtask initial begin reset <= 1; d <= $random; @(negedge clk); @(negedge clk); wavedrom_start(); reset_test(); repeat(10) @(negedge clk) d <= $random; wavedrom_stop(); repeat(400) @(posedge clk, negedge clk) reset <= !($random & 15); d <= $random; #1 $finish; end endtask module tb(); typedef struct {int errors; int errortime; int errors_q; int errortime_q; int clocks;} stats; stats stats1; logic [511:0] wavedrom_title; logic wavedrom_enable; reg clk = 0; initial forever #5 clk = ~clk; logic [7:0] d; logic reset; logic [7:0] q_ref, q_dut; reg tb_match; wire tb_mismatch = ~tb_match; stimulus_gen stim1(clk, d, reset); RefModule good1(clk, d, reset, q_ref); TopModule top_module1(clk, d, reset, q_dut); bit strobe = 0; task wait_for_end; repeat(5) begin strobe <= !strobe; @(strobe); end endtask final begin if (stats1.errors_q) $display("SIMULATION FAILED - %0d MISMATCHES, FIRST AT %0d", stats1.errors_q, stats1.errortime_q); else $display("SIMULATION PASSED"); $display("Total: %0d/%0d", stats1.errors, stats1.clocks); $display("Time: %0d ps", $time); $finish; end task automatic wait_for_end; assign tb_match = ({q_ref} === ({q_ref} ^ {q_dut} ^ {q_ref})); always @(posedge clk, negedge clk) begin stats1.clocks++; if (!tb_match) begin if (stats1.errors == 0) stats1.errortime = $time; stats1.errors++; end if (q_ref !== (q_ref ^ q_dut ^ q_ref)) begin if (stats1.errors_q ==0) stats1.errortime_q = $time; stats1.errors_q++; end end initial #1000000 $display("TIMEOUT"); $finish; end endmodule